#include<bits/stdc++.h>using namespace std;int t;int n;int vis[55],ans;vector<int> vec;void dfs(int x){    if(ans>=n){        return;    }    if(x>=3){          if(vec[x-1]==vec[x-2]+vec[x-3]){             return;         }    }    if(x==n){      if(ans<n){          for(int i=0;i<vec.size();i++){              cout<<vec[i]<<' ';          }          cout<<'\n';          ans++;      }      return;    }    for(int i=1;i<=n;i++){        if(vis[i]==0){            vis[i]=1;            vec.push_back(i);            dfs(x+1);            vis[i]=0;            vec.pop_back();        }    }}int main(){    cin>>t;    while(t--){        cin>>n;        for(int i=1;i<=n;i++){            vis[i]=0;        }        vec.clear();        ans=0;        dfs(0);    }    return 0;}